// JobHuntDashboard.js
// Phase 1 of the Job-Hunting Copilot: CV parse -> skills profile, and a
// tracking dashboard for job applications (Saved -> Applied -> Interviewing
// -> Offer -> Rejected), each with a match score.
// Fully self-contained; reuses the existing AI endpoint. No edits to UserSpace.js.

import React, { useEffect, useMemo, useState } from "react";
import { onAuthStateChanged } from "firebase/auth";
import { auth } from "../../firebase/config";
import {
  STATUSES,
  parseCV,
  extractPdfText,
  scoreJobMatch,
  searchJobs,
  estimateMatch,
  loadApplications,
  saveApplications,
  loadProfile,
  saveProfile,
  fetchRemote,
  pushRemote,
} from "./jobHuntData";
import "./JobHuntDashboard.css";

function ScoreRing({ score }) {
  const color = score >= 80 ? "#4CAF50" : score >= 60 ? "#FF9800" : "#f44336";
  const dash = (score / 100) * 2 * Math.PI * 22;
  return (
    <div className="jh-ring">
      <svg viewBox="0 0 60 60">
        <circle cx="30" cy="30" r="22" fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth="6" />
        <circle
          cx="30"
          cy="30"
          r="22"
          fill="none"
          stroke={color}
          strokeWidth="6"
          strokeLinecap="round"
          strokeDasharray={`${dash} 999`}
          transform="rotate(-90 30 30)"
        />
      </svg>
      <span className="jh-ring-val" style={{ color }}>
        {score}
      </span>
    </div>
  );
}

function StatTile({ label, value, accent }) {
  return (
    <div className="jh-stat">
      <div className="jh-stat-val" style={{ color: accent }}>
        {value}
      </div>
      <div className="jh-stat-label">{label}</div>
    </div>
  );
}

export default function JobHuntDashboard({ embedded = false, onTailor }) {
  const [profile, setProfile] = useState(loadProfile());
  const [apps, setApps] = useState([]);
  const [filter, setFilter] = useState("all");
  const [cvBusy, setCvBusy] = useState(false);
  const [cvError, setCvError] = useState("");
  const [rescoringId, setRescoringId] = useState(null);
  const [showProfile, setShowProfile] = useState(false);
  const [synced, setSynced] = useState(false);

  // Live search
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [searchError, setSearchError] = useState("");
  const [searchedOnce, setSearchedOnce] = useState(false);
  const [aiScoring, setAiScoring] = useState(false);
  const [aiProgress, setAiProgress] = useState({ done: 0, total: 0 });

  // Fast path: localStorage is the immediate source of truth.
  useEffect(() => {
    setApps(loadApplications());
  }, []);

  // When auth resolves, pull the Firestore mirror (if any) and reconcile.
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      if (!user) {
        setSynced(false);
        return;
      }
      const remote = await fetchRemote();
      if (remote?.applications?.length) {
        setApps(remote.applications);
        saveApplications(remote.applications);
      } else {
        // First login on this account: seed the cloud from local data.
        pushRemote({ applications: loadApplications(), profile: loadProfile() });
      }
      if (remote?.profile) {
        setProfile(remote.profile);
        saveProfile(remote.profile);
      }
      setSynced(true);
    });
    return () => unsub();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const persist = (next) => {
    setApps(next);
    saveApplications(next);
    pushRemote({ applications: next, profile });
  };

  const updateApp = (id, patch) =>
    persist(apps.map((a) => (a.id === id ? { ...a, ...patch } : a)));

  const setStatus = (id, status) =>
    updateApp(id, {
      status,
      dateApplied:
        status === "applied"
          ? apps.find((a) => a.id === id)?.dateApplied || new Date().toISOString()
          : apps.find((a) => a.id === id)?.dateApplied,
    });

  const removeApp = (id) => persist(apps.filter((a) => a.id !== id));

  // ---- Stats ----
  const stats = useMemo(() => {
    const total = apps.length;
    const applied = apps.filter((a) =>
      ["applied", "interviewing", "offer"].includes(a.status)
    ).length;
    const interviews = apps.filter((a) => a.status === "interviewing").length;
    const avg = total
      ? Math.round(apps.reduce((s, a) => s + (a.matchScore || 0), 0) / total)
      : 0;
    return { total, applied, interviews, avg };
  }, [apps]);

  const filtered = useMemo(
    () =>
      (filter === "all" ? apps : apps.filter((a) => a.status === filter)).sort(
        (a, b) => (b.matchScore || 0) - (a.matchScore || 0)
      ),
    [apps, filter]
  );

  // Default the search box to the candidate's top target title.
  useEffect(() => {
    if (!query && profile.preferredTitles?.length) {
      setQuery(profile.preferredTitles[0]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [profile]);

  const trackedIds = useMemo(() => new Set(apps.map((a) => a.id)), [apps]);

  // ---- Live search ----
  const runSearch = async () => {
    if (!query.trim()) return;
    setSearching(true);
    setSearchError("");
    setSearchedOnce(true);
    try {
      const loc = (profile.preferredLocations || []).find(
        (l) => l && l.toLowerCase() !== "remote"
      );
      const jobs = await searchJobs({
        query: query.trim(),
        location: loc || "",
        country: "in",
        limit: 20,
      });
      const scored = jobs
        .map((j) => {
          const est = estimateMatch(profile, j);
          return {
            ...j,
            matchScore: est.overallMatchScore,
            matchReasons: est.matchedSkills,
            gaps: [],
          };
        })
        .sort((a, b) => b.matchScore - a.matchScore);
      setResults(scored);
      if (scored.length === 0)
        setSearchError("No jobs found — try a broader title.");
    } catch (err) {
      setSearchError(err.message || "Search failed");
    } finally {
      setSearching(false);
    }
  };

  // Batch AI scoring of the visible search results (top 12 to control quota).
  const scoreAllResults = async () => {
    if (!results.length || aiScoring) return;
    setAiScoring(true);
    const top = results.slice(0, 12);
    setAiProgress({ done: 0, total: top.length });
    let updated = [...results];
    for (let i = 0; i < top.length; i++) {
      try {
        const r = await scoreJobMatch(profile, top[i]);
        const idx = updated.findIndex((x) => x.id === top[i].id);
        if (idx > -1) {
          updated[idx] = {
            ...updated[idx],
            matchScore: r.overallMatchScore,
            matchReasons: r.matchedSkills || updated[idx].matchReasons,
            gaps: r.gaps || [],
            aiScored: true,
          };
        }
      } catch (e) {
        /* keep the local estimate on failure */
      }
      setAiProgress({ done: i + 1, total: top.length });
      updated = [...updated].sort((a, b) => b.matchScore - a.matchScore);
      setResults(updated);
    }
    setAiScoring(false);
  };

  const trackJob = (job) => {
    if (trackedIds.has(job.id)) return;
    persist([
      {
        ...job,
        status: "saved",
        notes: "",
        dateAdded: new Date().toISOString(),
        dateApplied: null,
      },
      ...apps,
    ]);
  };

  const applyToJob = (job) => {
    if (job.url) window.open(job.url, "_blank", "noopener,noreferrer");
    setStatus(job.id, "applied");
  };

  // ---- CV upload ----
  const onCvFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCvBusy(true);
    setCvError("");
    try {
      let text = "";
      if (file.type === "application/pdf" || file.name.endsWith(".pdf")) {
        text = await extractPdfText(file);
      } else {
        text = await file.text();
      }
      if (!text || text.length < 50)
        throw new Error("Could not read enough text from that file.");
      const parsed = await parseCV(text);
      setProfile(parsed);
      saveProfile(parsed);
      pushRemote({ applications: apps, profile: parsed });
      setShowProfile(true);
    } catch (err) {
      setCvError(err.message || "Failed to parse CV");
    } finally {
      setCvBusy(false);
      e.target.value = "";
    }
  };

  const rescore = async (job) => {
    setRescoringId(job.id);
    try {
      const result = await scoreJobMatch(profile, job);
      updateApp(job.id, {
        matchScore: result.overallMatchScore,
        matchReasons: result.matchedSkills || job.matchReasons,
        gaps: result.gaps || job.gaps,
      });
    } catch (err) {
      /* keep existing score on failure */
    } finally {
      setRescoringId(null);
    }
  };

  const removeSkill = (list, val) => {
    const next = { ...profile, [list]: profile[list].filter((s) => s !== val) };
    setProfile(next);
    saveProfile(next);
    pushRemote({ applications: apps, profile: next });
  };

  return (
    <div className={`jobhunt-root ${embedded ? "embedded" : ""}`}>
      {/* Header */}
      <div className="jh-header">
        <div>
          <h1>🎯 Job-Hunting Copilot</h1>
          <p className="jh-sub">
            Parse your CV · match real jobs · track every application
            <span className={`jh-sync ${synced ? "on" : ""}`}>
              {synced ? "☁ Synced" : "💾 Local"}
            </span>
          </p>
        </div>
        <div className="jh-stats">
          <StatTile label="Tracked" value={stats.total} accent="#8892ff" />
          <StatTile label="Applied" value={stats.applied} accent="#2196F3" />
          <StatTile label="Interviews" value={stats.interviews} accent="#FF9800" />
          <StatTile label="Avg Match" value={`${stats.avg}%`} accent="#4CAF50" />
        </div>
      </div>

      {/* CV Parser */}
      <div className="jh-cv-panel">
        <div className="jh-cv-head">
          <div>
            <h3>📄 Candidate Profile</h3>
            <span className="jh-cv-name">
              {profile.fullName} — {profile.headline}
            </span>
          </div>
          <div className="jh-cv-actions">
            <label className="jh-btn primary">
              {cvBusy ? "Parsing…" : "Upload CV"}
              <input
                type="file"
                accept=".pdf,.txt,.md"
                onChange={onCvFile}
                disabled={cvBusy}
                hidden
              />
            </label>
            <button
              className="jh-btn ghost"
              onClick={() => setShowProfile((s) => !s)}
            >
              {showProfile ? "Hide skills" : "Show skills"}
            </button>
          </div>
        </div>
        {cvError && <div className="jh-error">{cvError}</div>}
        {showProfile && (
          <div className="jh-profile">
            <div className="jh-skill-group">
              <span className="jh-skill-label">Core skills</span>
              <div className="jh-chips">
                {profile.coreSkills?.map((s) => (
                  <span key={s} className="jh-chip">
                    {s}
                    <button onClick={() => removeSkill("coreSkills", s)}>×</button>
                  </span>
                ))}
              </div>
            </div>
            <div className="jh-skill-group">
              <span className="jh-skill-label">Tools</span>
              <div className="jh-chips">
                {profile.tools?.map((s) => (
                  <span key={s} className="jh-chip subtle">
                    {s}
                    <button onClick={() => removeSkill("tools", s)}>×</button>
                  </span>
                ))}
              </div>
            </div>
            <div className="jh-skill-group">
              <span className="jh-skill-label">Targeting</span>
              <div className="jh-chips">
                {profile.preferredTitles?.map((s) => (
                  <span key={s} className="jh-chip role">
                    {s}
                  </span>
                ))}
                {profile.preferredLocations?.map((s) => (
                  <span key={s} className="jh-chip loc">
                    📍 {s}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Live search */}
      <div className="jh-search-panel">
        <div className="jh-search-bar">
          <input
            className="jh-search-input"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && runSearch()}
            placeholder="Search live jobs — e.g. Generative AI Engineer"
          />
          <button
            className="jh-btn primary"
            onClick={runSearch}
            disabled={searching || !query.trim()}
          >
            {searching ? "Searching…" : "🔎 Find Jobs"}
          </button>
        </div>
        <div className="jh-search-meta">
          Live jobs via Adzuna (India + remote), with Remotive fallback. Scored
          against your CV.
        </div>
        {searchError && <div className="jh-error">{searchError}</div>}
        {results.length > 0 && (
          <div className="jh-results-toolbar">
            <span className="jh-results-count">
              {results.length} results · scored locally
            </span>
            <button
              className="jh-btn tiny ghost"
              onClick={scoreAllResults}
              disabled={aiScoring}
              title="Re-score the top results with AI for accurate matches"
            >
              {aiScoring
                ? `🤖 Scoring ${aiProgress.done}/${aiProgress.total}…`
                : "🤖 AI-score all"}
            </button>
          </div>
        )}
        {results.length > 0 && (
          <div className="jh-results">
            {results.map((job) => {
              const isTracked = trackedIds.has(job.id);
              return (
                <div className="jh-result" key={job.id}>
                  <ScoreRing score={job.matchScore} />
                  <div className="jh-job-main">
                    <div className="jh-job-top">
                      <a
                        href={job.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="jh-job-title"
                      >
                        {job.title}
                      </a>
                      <span className="jh-job-source">{job.source}</span>
                    </div>
                    <div className="jh-job-meta">
                      <strong>{job.company}</strong>
                      <span>· {job.location}</span>
                      {job.jobType && <span>· {job.jobType}</span>}
                    </div>
                    {(job.aiScored || job.matchReasons?.length > 0) && (
                      <div className="jh-tags">
                        {job.aiScored && (
                          <span className="jh-tag ai">🤖 AI-scored</span>
                        )}
                        {(job.matchReasons || []).slice(0, 6).map((r) => (
                          <span key={r} className="jh-tag good">
                            {r}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                  <button
                    className={`jh-btn tiny ${isTracked ? "ghost" : "primary"}`}
                    onClick={() => trackJob(job)}
                    disabled={isTracked}
                  >
                    {isTracked ? "✓ Tracked" : "➕ Track"}
                  </button>
                </div>
              );
            })}
          </div>
        )}
        {searchedOnce && !searching && results.length === 0 && !searchError && (
          <div className="jh-empty">No results.</div>
        )}
      </div>

      {/* Pipeline filter */}
      <div className="jh-filters">
        <button
          className={`jh-filter ${filter === "all" ? "active" : ""}`}
          onClick={() => setFilter("all")}
        >
          All <span className="jh-count">{apps.length}</span>
        </button>
        {STATUSES.map((s) => (
          <button
            key={s.id}
            className={`jh-filter ${filter === s.id ? "active" : ""}`}
            onClick={() => setFilter(s.id)}
            style={filter === s.id ? { borderColor: s.color } : {}}
          >
            {s.icon} {s.label}
            <span className="jh-count">
              {apps.filter((a) => a.status === s.id).length}
            </span>
          </button>
        ))}
      </div>

      {/* Job cards */}
      <div className="jh-jobs">
        {filtered.length === 0 && (
          <div className="jh-empty">No jobs in this stage yet.</div>
        )}
        {filtered.map((job) => {
          const st = STATUSES.find((s) => s.id === job.status) || STATUSES[0];
          return (
            <div className="jh-job" key={job.id}>
              <ScoreRing score={job.matchScore || 0} />
              <div className="jh-job-main">
                <div className="jh-job-top">
                  <a
                    href={job.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="jh-job-title"
                  >
                    {job.title}
                  </a>
                  <span className="jh-job-source">{job.source}</span>
                </div>
                <div className="jh-job-meta">
                  <strong>{job.company}</strong>
                  <span>· {job.location}</span>
                  {job.jobType && <span>· {job.jobType}</span>}
                </div>
                {job.matchReasons?.length > 0 && (
                  <div className="jh-tags">
                    {job.matchReasons.slice(0, 5).map((r) => (
                      <span key={r} className="jh-tag good">
                        {r}
                      </span>
                    ))}
                    {job.gaps?.slice(0, 3).map((g) => (
                      <span key={g} className="jh-tag gap">
                        gap: {g}
                      </span>
                    ))}
                  </div>
                )}
              </div>
              <div className="jh-job-actions">
                <select
                  className="jh-status-select"
                  value={job.status}
                  onChange={(e) => setStatus(job.id, e.target.value)}
                  style={{ borderColor: st.color, color: st.color }}
                >
                  {STATUSES.map((s) => (
                    <option key={s.id} value={s.id}>
                      {s.icon} {s.label}
                    </option>
                  ))}
                </select>
                <button
                  className="jh-btn tiny primary"
                  onClick={() => applyToJob(job)}
                  title="Open the official apply page and mark as Applied"
                >
                  Apply ↗
                </button>
                {onTailor ? (
                  <button
                    className="jh-btn tiny"
                    onClick={() => onTailor(job)}
                    title="Send this JD to the Resume-Agent (pre-fills — paste the full JD there, then Analyze)"
                  >
                    ✨ Tailor
                  </button>
                ) : (
                  <a
                    href={`/myspace`}
                    className="jh-btn tiny"
                    title="Open Resume-Agent to tailor for this job"
                  >
                    ✨ Tailor
                  </a>
                )}
                <button
                  className="jh-btn tiny ghost"
                  onClick={() => rescore(job)}
                  disabled={rescoringId === job.id}
                >
                  {rescoringId === job.id ? "…" : "↻ Rescore"}
                </button>
                <button
                  className="jh-btn tiny danger"
                  onClick={() => removeApp(job.id)}
                >
                  ✕
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
