// jobHuntData.js
// Self-contained data + logic layer for the Job-Hunting Copilot (Phase 1).
// Reuses the existing Firebase "callGeminiHTTP" endpoint (Gemini -> Groq fallback)
// that UserSpace.js already uses, so no new backend is required.
// Persistence: localStorage (single-user). Easy to swap for Firestore later.

import * as pdfjsLib from "pdfjs-dist";
import { doc, getDoc, setDoc } from "firebase/firestore";
import { db, auth } from "../../firebase/config";

// Match the worker to the *installed* pdfjs version so they can't drift.
// (pdfjs-dist v5 ships an ESM worker: pdf.worker.min.mjs)
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

// ===== AI ENDPOINT (same as UserSpace.callGeminiAPI) =====
const AI_ENDPOINT =
  "https://us-central1-portfolio-142b7.cloudfunctions.net/callGeminiHTTP";

export async function callAI(prompt, maxTokens = 2048) {
  const response = await fetch(AI_ENDPOINT, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ prompt, maxTokens }),
  });
  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(`AI ${response.status}: ${err.error || response.statusText}`);
  }
  const data = await response.json();
  const text = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
  if (!text) throw new Error("Empty AI response");
  return text;
}

// Pull the first balanced JSON object/array out of a model response
// (handles ```json fences and surrounding prose).
export function extractJSON(text) {
  if (!text) return null;
  let cleaned = text.trim();
  cleaned = cleaned.replace(/```json/gi, "").replace(/```/g, "").trim();
  const start = cleaned.search(/[[{]/);
  if (start === -1) return null;
  const open = cleaned[start];
  const close = open === "{" ? "}" : "]";
  let depth = 0;
  let inStr = false;
  let esc = false;
  for (let i = start; i < cleaned.length; i++) {
    const ch = cleaned[i];
    if (esc) {
      esc = false;
      continue;
    }
    if (ch === "\\") {
      esc = true;
      continue;
    }
    if (ch === '"') inStr = !inStr;
    if (inStr) continue;
    if (ch === open) depth++;
    else if (ch === close) {
      depth--;
      if (depth === 0) {
        try {
          return JSON.parse(cleaned.slice(start, i + 1));
        } catch (e) {
          return null;
        }
      }
    }
  }
  return null;
}

// ===== CV -> TEXT (PDF) =====
export async function extractPdfText(file) {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  let text = "";
  for (let p = 1; p <= pdf.numPages; p++) {
    const page = await pdf.getPage(p);
    const content = await page.getTextContent();
    text += content.items.map((i) => i.str).join(" ") + "\n";
  }
  return text.trim();
}

// ===== CV -> STRUCTURED PROFILE =====
export async function parseCV(cvText) {
  const prompt = `You are an expert technical recruiter and CV parser.
Extract a structured candidate profile from the CV text below.
Return ONLY valid JSON, no markdown, matching exactly this shape:
{
  "fullName": "string",
  "headline": "one-line professional headline",
  "yearsExperience": number,
  "seniority": "Junior | Mid | Senior | Lead",
  "coreSkills": ["most important skills, max 15"],
  "tools": ["languages, frameworks, platforms, max 15"],
  "domains": ["industry / problem domains, max 6"],
  "preferredTitles": ["job titles this candidate should target, max 6"],
  "preferredLocations": ["locations incl. Remote if applicable, max 5"],
  "summary": "2-sentence summary of the candidate"
}

CV TEXT:
${cvText.slice(0, 12000)}`;

  const raw = await callAI(prompt, 2048);
  const parsed = extractJSON(raw);
  if (!parsed) throw new Error("Could not parse CV into a profile");
  return parsed;
}

// ===== JOB MATCH SCORING =====
export async function scoreJobMatch(profile, job) {
  const prompt = `You are a career advisor scoring how well a candidate matches a job.
Return ONLY valid JSON, no markdown, matching exactly:
{
  "overallMatchScore": number (0-100),
  "matchedSkills": ["skills the candidate clearly has that the job wants, max 8"],
  "gaps": ["skills/requirements the candidate may be missing, max 5"],
  "summary": "one-sentence verdict"
}

CANDIDATE PROFILE:
${JSON.stringify(
  {
    seniority: profile.seniority,
    coreSkills: profile.coreSkills,
    tools: profile.tools,
    domains: profile.domains,
    yearsExperience: profile.yearsExperience,
  },
  null,
  2
)}

JOB:
Title: ${job.title}
Company: ${job.company}
Location: ${job.location}
${job.jd ? `Description: ${job.jd.slice(0, 4000)}` : ""}`;

  const raw = await callAI(prompt, 1024);
  const parsed = extractJSON(raw);
  if (!parsed) throw new Error("Could not score job match");
  return parsed;
}

// ===== LIVE JOB SEARCH (free, no-key, CORS-open sources) =====
// Remotive is the primary source: real search param, strong AI/ML/tech coverage.
// Paid/keyed sources (JSearch, Adzuna) can be added later behind this same
// signature via a Firebase Function proxy — the UI won't need to change.

export function stripHtml(html) {
  if (!html) return "";
  try {
    const tmp = document.createElement("div");
    tmp.innerHTML = html;
    return (tmp.textContent || tmp.innerText || "").replace(/\s+/g, " ").trim();
  } catch (e) {
    return html.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim();
  }
}

// Synonyms/aliases so exact-substring matching doesn't miss obvious hits
// (Adzuna only returns a ~500-char snippet, so every real match counts).
const SKILL_ALIASES = {
  llms: ["llm", "large language model", "language model", "gpt", "transformer"],
  "agentic ai": ["agent", "agentic", "multi-agent", "multi agent", "autonomous agent"],
  "multi-agent systems": ["multi-agent", "multi agent", "agent orchestration", "agentic"],
  rag: ["rag", "retrieval augmented", "retrieval-augmented"],
  gemini: ["gemini", "vertex", "google ai"],
  "vertex ai": ["vertex", "google cloud", "gcp"],
  gcp: ["gcp", "google cloud", "google cloud platform"],
  "prompt engineering": ["prompt engineering", "prompting", "prompt design"],
  "vector search": ["vector search", "vector database", "vector db", "embeddings", "pinecone", "faiss"],
  langgraph: ["langgraph", "lang graph", "langchain"],
  langchain: ["langchain", "lang chain"],
  crewai: ["crewai", "crew ai"],
  mcp: ["model context protocol", "mcp"],
  pytorch: ["pytorch", "torch"],
  tensorflow: ["tensorflow"],
  bigquery: ["bigquery", "big query"],
  "cloud run": ["cloud run"],
  "dialogflow cx": ["dialogflow"],
  "generative ai": ["generative ai", "gen ai", "genai"],
};

function skillHits(skill, hay) {
  const key = skill.toLowerCase();
  const variants = new Set([key, key.replace(/[-/]/g, " ")]);
  (SKILL_ALIASES[key] || []).forEach((a) => variants.add(a));
  return [...variants].some((v) => v && hay.includes(v));
}

// Fast, local, no-API estimate so results render instantly.
// The AI `scoreJobMatch` ("Rescore" / "AI-score all") refines on demand.
export function estimateMatch(profile, job) {
  const fullHay = `${job.title} ${job.jd || ""}`.toLowerCase();
  const titleHay = (job.title || "").toLowerCase();
  const skills = [
    ...new Set([...(profile.coreSkills || []), ...(profile.tools || [])]),
  ].filter(Boolean);

  const matched = skills.filter((s) => skillHits(s, fullHay));
  const matchedInTitle = skills.filter((s) => skillHits(s, titleHay));
  const roleHit = (profile.preferredTitles || []).some((t) => {
    const first = (t || "").toLowerCase().split(" ")[0];
    return first && titleHay.includes(first);
  });

  const coverage = matched.length / Math.max(6, skills.length); // 0..1
  let score = 45 + coverage * 45; // skills coverage → 45..90
  score += Math.min(matchedInTitle.length * 3, 12); // title skill hits
  if (roleHit) score += 6; // title matches a target role
  score = Math.max(40, Math.min(97, Math.round(score)));

  return { overallMatchScore: score, matchedSkills: matched.slice(0, 6) };
}

// Adzuna proxy (local + remote, India-capable). Key is server-side in the
// Firebase Function; the browser only ever hits this endpoint.
const SEARCH_ENDPOINT =
  "https://us-central1-portfolio-142b7.cloudfunctions.net/searchJobs";

async function searchAdzuna({ query, location = "", country = "in", limit }) {
  const params = new URLSearchParams({
    query,
    location,
    country,
    results_per_page: String(limit),
  });
  const res = await fetch(`${SEARCH_ENDPOINT}?${params.toString()}`);
  if (!res.ok) throw new Error(`Adzuna proxy ${res.status}`);
  const data = await res.json();
  if (!Array.isArray(data.jobs)) throw new Error("Bad Adzuna response");
  return data.jobs;
}

// Keyless fallback (remote roles only) — works even before the function deploys.
async function searchRemotive({ query, limit }) {
  const url = `https://remotive.com/api/remote-jobs?search=${encodeURIComponent(
    query
  )}&limit=${limit}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Remotive ${res.status}`);
  const data = await res.json();
  return (data.jobs || []).map((j) => ({
    id: `remotive_${j.id}`,
    title: j.title,
    company: j.company_name,
    location: j.candidate_required_location || "Remote",
    url: j.url,
    source: "Remotive",
    jobType: (j.job_type || "").replace(/_/g, " "),
    postedOn: (j.publication_date || "").slice(0, 10),
    jd: stripHtml(j.description).slice(0, 6000),
  }));
}

export async function searchJobs({
  query,
  location = "",
  country = "in",
  limit = 20,
}) {
  try {
    return await searchAdzuna({ query, location, country, limit });
  } catch (e) {
    // Function not deployed / network issue -> degrade gracefully to Remotive.
    return await searchRemotive({ query, limit });
  }
}

