// ===== LOCALSTORAGE PERSISTENCE =====
const JOBS_KEY = "jobhunt.applications.v1";
const PROFILE_KEY = "jobhunt.profile.v1";

export function loadApplications() {
  try {
    const raw = localStorage.getItem(JOBS_KEY);
    if (raw) return JSON.parse(raw);
  } catch (e) {
    /* ignore */
  }
  // First run: seed the pipeline with real jobs in "saved".
  const seeded = SEED_JOBS.map((j) => ({
    ...j,
    status: "saved",
    notes: "",
    dateAdded: new Date().toISOString(),
    dateApplied: null,
  }));
  saveApplications(seeded);
  return seeded;
}

export function saveApplications(apps) {
  try {
    localStorage.setItem(JOBS_KEY, JSON.stringify(apps));
  } catch (e) {
    /* ignore */
  }
}

export function loadProfile() {
  try {
    const raw = localStorage.getItem(PROFILE_KEY);
    if (raw) return JSON.parse(raw);
  } catch (e) {
    /* ignore */
  }
  return DEFAULT_PROFILE;
}

export function saveProfile(profile) {
  try {
    localStorage.setItem(PROFILE_KEY, JSON.stringify(profile));
  } catch (e) {
    /* ignore */
  }
}

// ===== FIRESTORE SYNC (used when the user is logged in) =====
// Single doc per user at jobhunt/{uid}: { applications, profile, updatedAt }.
// localStorage stays the fast, offline source of truth; Firestore is the
// cross-device mirror. Both are written on every save.

export function currentUid() {
  return auth?.currentUser?.uid || null;
}

// Returns { applications, profile } from Firestore, or null if none / not logged in.
export async function fetchRemote() {
  const uid = currentUid();
  if (!uid) return null;
  try {
    const snap = await getDoc(doc(db, "jobhunt", uid));
    if (snap.exists()) return snap.data();
    return null;
  } catch (e) {
    return null;
  }
}

export async function pushRemote({ applications, profile }) {
  const uid = currentUid();
  if (!uid) return;
  try {
    await setDoc(
      doc(db, "jobhunt", uid),
      { applications, profile, updatedAt: Date.now() },
      { merge: true }
    );
  } catch (e) {
    /* offline / rules -> localStorage still holds the data */
  }
}
